sinks.expression:
array_map(
			static function ( $line ) use ( &$value ) {
				if ( preg_match( '/(?<![; ])\s*?(max_input_vars).*?=\D*?(\d+)/i', $line, $matches ) ) {
					$value = (int) $matches[2];
				}
			},
			$content_arr
		)

array_filter(
			$content_arr,
			static function ( $line ) {
				return false === strpos( $line, 'max_input_vars' );
			}
		)

array_filter(
			$tabs,
			static function ( $tab ) {
				return is_a( $tab, Tables::class );
			}
		)

